INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('heelevel3-29a002de-moex-00091', 'heelevel3-29a002de', 'heelevel3-29a002de-moex-113-9b7ab1bb', 'sub-heelevel3-29a002de-03', NULL, 'single_choice', '下列關於遺產繼承人之敘述，何者正確？ 繼承人若有於繼承開始後死亡或喪失繼承權者，由其直系血親卑親屬代位繼承其應繼分 繼承人對於被繼承人有重大之虐待或侮辱情事，並經被繼承人表示其不得繼承者，其繼承權喪失 繼承人有數人，其中一人若受監護或輔助宣告者，法院得依其他繼承人之請求，宣告該繼承人 之繼承權喪失 同一順序之繼承人有數人時，按人數平均繼承。但非婚生子女之應繼分，為婚生子女應繼分之 二分之一', '["", "", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:38+00:00", "source_pdf_sha1": "60d353c92096", "answer_pdf_sha1": "72b927f36aec", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "324", "s": "1004", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 23, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "heelevel3", "civil_category": "司法行政"}'::jsonb, NULL),
  ('heelevel3-29a002de-moex-00092', 'heelevel3-29a002de', 'heelevel3-29a002de-moex-113-9b7ab1bb', 'sub-heelevel3-29a002de-03', NULL, 'single_choice', '甲死亡時，留下存款新臺幣（下同）240 萬元，有配偶乙、兄丙、姊丁及妹戊為其繼承人。丁應 可繼承多少甲之遺產？ 40萬元  60萬元  80 萬元  120萬元', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:38+00:00", "source_pdf_sha1": "60d353c92096", "answer_pdf_sha1": "72b927f36aec", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "324", "s": "1004", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 24, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "heelevel3", "civil_category": "司法行政"}'::jsonb, NULL),
  ('heelevel3-29a002de-moex-00093', 'heelevel3-29a002de', 'heelevel3-29a002de-moex-113-9b7ab1bb', 'sub-heelevel3-29a002de-03', NULL, 'single_choice', '下列關於代位繼承之敘述，何者錯誤？ 代位繼承係以自己固有之繼承權直接繼承祖父母之遺產 代位繼承係以自己固有之繼承權繼承父或母之權利 孫對於祖父母之遺產，有無代位繼承之資格，自應以祖父母之繼承開始為標準而決定之 子女對父或母之遺產拋棄繼承，不能即謂對祖父母之遺產拋棄代位繼承', '["", "", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:38+00:00", "source_pdf_sha1": "60d353c92096", "answer_pdf_sha1": "72b927f36aec", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "324", "s": "1004", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 25, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "heelevel3", "civil_category": "司法行政"}'::jsonb, NULL),
  ('heelevel3-29a002de-moex-00094', 'heelevel3-29a002de', 'heelevel3-29a002de-moex-112-916530c6', 'sub-heelevel3-29a002de-01', NULL, 'essay', '甲男駕車載女友乙以及乙的母親丙到郊外餐廳，想要討論甲、乙計畫結婚
之事。車子行經十字路口，甲無任何疏失竟遭開車闖紅燈的丁撞擊，甲、
乙兩人僅受輕傷，丁則是受到驚嚇，全身癱軟，而坐在甲車後座的丙由於
直接受撞擊，多處骨折且血流不止。乙女本來已經拿出手機要呼叫救護車
將丙送醫急救，但甲想到丙一直阻攔他跟乙的婚事，遂勸乙不要救丙。乙
因為深愛甲，很想跟甲雙宿雙飛，雖明知不將丙送醫，丙將丟掉性命，但
仍狠下心來，不招救護車將丙送醫，嗣後丙果然因為延誤送醫流血過多死
亡。試問甲、乙觸犯刑法上何罪名？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:38+00:00", "source_pdf_sha1": "066b733ee4bb", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "328", "s": "1211", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "刑法", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "司法行政"}'::jsonb, NULL),
  ('heelevel3-29a002de-moex-00095', 'heelevel3-29a002de', 'heelevel3-29a002de-moex-112-916530c6', 'sub-heelevel3-29a002de-01', NULL, 'essay', '甲沒有大客車駕駛執照，聽聞擔任遊覽車司機的朋友乙因為生病無法上
班，甲為了既能幫助朋友，自己也能賺點外快，便到乙任職公司佯稱自己
有大客車駕駛執照，且願意幫乙代班。遊覽車公司老闆見甲一臉老實，信
以為真，便讓甲開車出團。孰料，沒開過遊覽車的甲開車技術並不足以駕
駛遊覽車，因為不熟悉大客車後視鏡的使用，在轉彎時雖然已經極為注
意，但仍輾斃一旁騎機車的老翁A。試問甲有何刑責？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:38+00:00", "source_pdf_sha1": "066b733ee4bb", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "328", "s": "1211", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "刑法", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "司法行政"}'::jsonb, NULL),
  ('heelevel3-29a002de-moex-00096', 'heelevel3-29a002de', 'heelevel3-29a002de-moex-112-916530c6', 'sub-heelevel3-29a002de-01', NULL, 'essay', '律師甲受某政治人物的妻子A委任，為A處理案件。甲將部分卷宗帶回家
中閱讀，但因疏忽將卷宗打開放在桌上，不料竟被甲的妻子乙看到一文
件，證實坊間傳聞A被其丈夫家暴一事。乙平常即對該政治人物的言論極
為不滿，遂向甲「曉以大義」，要求將此文件內容傳給媒體報導公諸於世。
甲禁不起乙的勸說洗腦，便跟乙共同將此文件影印後寄給報社刊登。嗣後
A對甲、乙兩人提出告訴，試問甲、乙有何刑責？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:38+00:00", "source_pdf_sha1": "066b733ee4bb", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "328", "s": "1211", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "刑法", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": "三", "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "司法行政"}'::jsonb, NULL),
  ('heelevel3-29a002de-moex-00097', 'heelevel3-29a002de', 'heelevel3-29a002de-moex-112-916530c6', 'sub-heelevel3-29a002de-01', NULL, 'essay', '甲對乙佯稱自己是某黑幫的堂主，手下小弟都兇狠無比，因為前陣子殺了
人，現在正在跑路，想要乙贊助一萬元的跑路費，不然就要叫手下小弟把
乙帶到山上殺死埋掉。乙聽到後驚恐無比，遂湊了一萬元交給甲。嗣經證
實甲事實上只是個小混混，平時只敢做點雞鳴狗盜之事，甲當時對乙所說
殺死埋掉，只是為了唬弄乙，意欲得財而已。試問甲有何刑責？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:38+00:00", "source_pdf_sha1": "066b733ee4bb", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "328", "s": "1211", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "刑法", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": "四", "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "司法行政"}'::jsonb, NULL),
  ('heelevel3-29a002de-moex-00098', 'heelevel3-29a002de', 'heelevel3-29a002de-moex-112-e733516d', 'sub-heelevel3-29a002de-02', NULL, 'essay', '甲男與乙女結婚數年後，甲男以乙女與丙男有婚外情，訴請判決離婚。甲
男起訴後，並追加聲明謂，請求法院依夫妻剩餘財產差額分配請求權，判
決乙女應給付甲男新臺幣（下同）300萬元；並請求乙女返還其代為墊付
乙女年邁父母居住於安養中心費用之不當得利30萬元。同時，甲男請求追
加第三人丙男為共同被告，主張丙男妨害家庭之行為，致甲男產生名譽上
重大損害，請求法院判決乙、丙應連帶給付甲男200萬元。試問：受訴法
院對甲男聲明之各項追加，如何審理？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:38+00:00", "source_pdf_sha1": "581084720152", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "328", "s": "1210", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "民事訴訟法與刑事訴訟法", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "司法行政"}'::jsonb, NULL),
  ('heelevel3-29a002de-moex-00099', 'heelevel3-29a002de', 'heelevel3-29a002de-moex-112-e733516d', 'sub-heelevel3-29a002de-02', NULL, 'essay', '甲主張其為A屋所有人，將A屋出租於乙，惟甲、乙之租約已到期，且乙
於租約到期後仍住A屋長達2年。甲遂以乙為被告，列先、備位請求為，先
位請求：請求乙返還租賃物A屋，並給付相當於兩年房租租金之不當得利
共計新臺幣（下同）200萬元。備位請求：請求乙返還所有物A屋，並給付
其損害所有權之賠償共計200萬元。乙於第一審準備程序時，向法院提出
主張謂，甲並非A屋所有人，該A屋為乙另向真正所有人丙（即甲之配偶）
承租。且乙、丙曾以手機簡訊同意租期為5年，乙並有手機截圖為證。同
時，乙提出反訴，主張甲應為該濫訴致生毀損乙之名譽，給付其精神損害
賠償200萬元。試問：審判長就本件當事人甲、乙所提出之各項主張，應
進行如何之闡明，並指揮爭點整理程序？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:38+00:00", "source_pdf_sha1": "581084720152", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "328", "s": "1210", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "民事訴訟法與刑事訴訟法", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "司法行政"}'::jsonb, NULL),
  ('heelevel3-29a002de-moex-00100', 'heelevel3-29a002de', 'heelevel3-29a002de-moex-112-e733516d', 'sub-heelevel3-29a002de-02', NULL, 'essay', '甲具有原住民身分，涉犯殺人罪。偵查中，檢察官依法通知法律扶助基金
會指派律師乙擔任甲的辯護人，並向法院聲請羈押甲。羈押審查程序期
日，乙沒有到場且無法取得聯繫。請問：根據刑事訴訟法，法院能否在乙
缺席下審查對甲的羈押聲請？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:38+00:00", "source_pdf_sha1": "581084720152", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "328", "s": "1210", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "民事訴訟法與刑事訴訟法", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": "三", "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "司法行政"}'::jsonb, NULL)
